import React, {useMemo} from "react";
import type {IButtonProps, IconName} from "@lmb-it/kitsconcerto-types";
import {useButton} from "./useButton.js";
import {ResponsiveElement, useSeparator} from "../../factory";
import {useLanguage, useComponentDefaults} from "../../hooks";
import {useSeverityColors} from "../../hooks/useSeverityColors";
import {IconMap} from "../../assets/Icons";

/* ─── Icon resolver ──────────────────────────────────────────── */
function resolveIcon(icon: unknown, color?: string): React.ReactNode {
    if (!icon) return null;
    // React element passed directly
    if (React.isValidElement(icon)) return icon;
    if (typeof icon !== 'string') return null;
    // PrimeReact icon class string (e.g. "pi pi-check")
    if (icon.startsWith('pi ')) {
        return <i className={icon} style={{fontSize: 'inherit', color: color ?? 'inherit'}} />;
    }
    // Lucide icon name from IconMap
    const Component = IconMap[icon as IconName];
    if (Component) return <Component size="1em" />;
    return null;
}

/* ─── Spinner for loading state ──────────────────────────────── */
const Spinner = ({color}: {color?: string}) => (
    <span
        style={{
            display: 'inline-block',
            width: '1em',
            height: '1em',
            border: '2px solid transparent',
            borderTopColor: color ?? 'currentColor',
            borderLeftColor: color ?? 'currentColor',
            borderRadius: '50%',
            animation: 'kits-btn-spin 0.6s linear infinite',
        }}
    />
);

/* ─── Size configuration ─────────────────────────────────────── */
const SIZE_MAP = {
    sm: {height: 32, fontSize: 12.25, px: 10, py: 6, gap: 6, iconSize: 14},
    md: {height: 40, fontSize: 14, px: 16, py: 10, gap: 8, iconSize: 16},
    lg: {height: 48, fontSize: 16, px: 24, py: 12, gap: 10, iconSize: 18},
} as const;

/* ─── Inject keyframes once ──────────────────────────────────── */
if (typeof document !== 'undefined') {
    const id = 'kits-btn-spin-keyframes';
    if (!document.getElementById(id)) {
        const sheet = document.createElement('style');
        sheet.id = id;
        sheet.textContent = `@keyframes kits-btn-spin { to { transform: rotate(360deg); } }`;
        document.head.appendChild(sheet);
    }
}

/* ─── Button Component ───────────────────────────────────────── */
export function Button(rawProps: IButtonProps<IconName | string | React.ReactNode>) {
    const {mergedProps: props, themeStyle, elementStyles} = useComponentDefaults('Button', rawProps);
    const {
        children,
        label,
        isLoadingText,
        severity,
        size = "md",
        loading,
        className,
        iconPos = "left",
        icon,
        id,
        testID,
        style,
        outlined,
        raised,
        rounded,
        tooltip,
        tooltipOptions,
        ...rest
    } = props;

    const {t} = useLanguage();
    const {cssProps, nativeProps} = useSeparator<HTMLButtonElement>(rest);
    const sevColors = useSeverityColors((severity as any) ?? 'brand');

    const {handlers, isDisabled} = useButton(props);

    const sizeConfig = SIZE_MAP[size as keyof typeof SIZE_MAP] ?? SIZE_MAP.md;

    /* ── Resolve label text ── */
    const resolvedLabel = typeof children === "string"
        ? children
        : loading && isLoadingText
            ? isLoadingText
            : t(label ?? "");

    /* ── Compute severity-based styles ──
     * Filled: bg=solid, text=solidText (defaults to white, overridable via kitsTheme)
     * Outlined: bg=transparent, text=solid, border=border
     * All values resolved through the full token system (colors, semanticTokens, dot-notation).
     */
    const severityStyles = useMemo(() => {
        if (outlined) {
            return {
                backgroundColor: 'transparent',
                color: sevColors.solid,
                borderColor: sevColors.border || sevColors.solid,
                borderWidth: '1px',
                borderStyle: 'solid' as const,
            };
        }
        return {
            backgroundColor: sevColors.solid,
            color: sevColors.solidText,
            borderColor: sevColors.border || sevColors.solid,
            borderWidth: '1px',
            borderStyle: 'solid' as const,
        };
    }, [outlined, sevColors]);

    /* ── Layout direction for iconPos ── */
    const isVertical = iconPos === 'top' || iconPos === 'bottom';
    const isReverse = iconPos === 'right' || iconPos === 'bottom';

    /* ── Resolved icon element ── */
    const iconElement = loading
        ? <Spinner color={severityStyles.color} />
        : resolveIcon(icon, severityStyles.color);

    const hasLabel = !!resolvedLabel;
    const isIconOnly = !hasLabel && !!iconElement;

    /* ── Build CSS props for ResponsiveElement ── */
    const computedCss = {
        ...themeStyle,
        ...(elementStyles.root || {}),
        ...cssProps,
        // Base button styles (matching PrimeReact defaults)
        display: 'inline-flex',
        alignItems: 'center',
        justifyContent: 'center',
        flexDirection: isVertical ? (isReverse ? 'column-reverse' : 'column') : (isReverse ? 'row-reverse' : 'row'),
        gap: hasLabel && iconElement ? sizeConfig.gap : 0,
        height: sizeConfig.height,
        // Icon-only: force width = height for a perfect square
        ...(isIconOnly ? { width: sizeConfig.height, minWidth: sizeConfig.height } : {}),
        paddingLeft: hasLabel ? sizeConfig.px : sizeConfig.py,
        paddingRight: hasLabel ? sizeConfig.px : sizeConfig.py,
        paddingTop: sizeConfig.py,
        paddingBottom: sizeConfig.py,
        fontSize: sizeConfig.fontSize,
        fontWeight: '600',
        fontFamily: 'inherit',
        lineHeight: 'normal',
        cursor: isDisabled ? 'not-allowed' : 'pointer',
        ...(isDisabled ? {opacity: '0.5'} : {}),
        transition: 'background-color 0.2s, color 0.2s, border-color 0.2s, box-shadow 0.2s, opacity 0.2s',
        textDecoration: 'none',
        userSelect: 'none',
        overflow: 'hidden',
        position: 'relative' as const,
        // Severity colors
        ...severityStyles,
        // Raised
        ...(raised ? {boxShadow: '0 3px 6px rgba(0,0,0,0.16), 0 3px 6px rgba(0,0,0,0.23)'} : {}),
        // Rounded
        ...(rounded ? {borderRadius: 9999} : {borderRadius: style?.borderRadius ?? 6}),
        // Style overrides from consumer
        ...style,
    };

    const nativeButtonProps = {
        ...nativeProps,
        id,
        type: (nativeProps as any)?.type ?? 'button',
        disabled: isDisabled,
        onClick: handlers.onClick,
        onMouseEnter: handlers.onMouseEnter,
        onMouseLeave: handlers.onMouseLeave,
        className,
        "data-testid": testID,
        title: tooltip,
        'aria-busy': loading || undefined,
        'aria-disabled': isDisabled || undefined,
    };

    return (
        <ResponsiveElement
            as="Button"
            //@ts-ignore
            cssProps={computedCss}
            nativeProps={nativeButtonProps}
            additionalStyles={{}}
        >
            {iconElement}
            {hasLabel && (
                <span style={{lineHeight: 'inherit', pointerEvents: 'none'}}>
                    {resolvedLabel}
                </span>
            )}
            {typeof children !== "string" ? children : undefined}
        </ResponsiveElement>
    );
}

export default Button;
